text:
{
  "formal_minutes": {
    "decisions": {
      "confirmed_decisions": [
        {
          "item": "릴리스 공개 일정을 금요일 15:00 KST로 확정하되, 스모크 테스트 통과가 선행되어야 한다.",
          "source": "회의록 원문"
        },
        {
          "item": "패키지 이름 불일치 시 `smoke-theme-pack.mjs`를 무시하도록 변경하는 제안은 반려되었고, packageName mismatch가 발생하면 우선 패키지 설정(계약/설정) 자체가 맞는지 확인하고, 계약이 잘못된 경우에만 스크립트를 검토한다.",
          "source": "회의록 원문"
        },
        {
          "item": "Minjun은 금요일 10:00 KST까지 스모크 테스트를 재실행하고 결과를 공유한다.",
          "source": "회의록 원문"
        },
        {
          "item": "Doyun은 금요일 12:00 KST까지 failure triage note를 `action_items.md`에 작성한다.",
          "source": "회의록 원문"
        }
      ],
      "rejected_proposals": [
        {
          "item": "Hara의 `smoke-theme-pack.mjs`에서 packageName mismatch를 무시하도록 변경하는 제안",
          "reason": "패키지 설정 자체 점검을 우선해야 한다는 합의로 반려됨"
        }
      ],
      "non_decisions": [
        {
          "item": "README 설치 가이드 검토(목요일 가능 시)는 제안되었으나 담당자와 확정 일정이 지정되지 않음"
        },
        {
          "item": "최종 릴리스 승인 권한자 지정 여부(권한자)는 미확정"
        },
        {
          "item": "릴리스 노트에 내부 수요일 stretch goal을 언급할지 여부는 미정"
        }
      ]
    },
    "internal_stretch_goals": [
      {
        "item": "수요일 안에 공개 전 스모크 테스트 통과를 시도한다는 내부 목표",
        "status": "스모크 통과 조건이 충족된 경우의 내부 목표로만 유지"
      }
    ],
    "risks": [
      {
        "item": "tarball 경로가 잘못되면 릴리스 지연 가능성"
      },
      {
        "item": "README 설치 단계가 오래되어 있을 경우 릴리스 노트/안내가 사용자에게 오해 유발 가능성"
      }
    ],
    "open_questions": [
      {
        "item": "최종 릴리스 승인 권한자는 누구인가?"
      },
      {
        "item": "릴리스 노트에 수요일 internal stretch goal을 명시할지 여부"
      }
    ]
  },
  "action_items": [
    {
      "owner": "Minjun",
      "task": "금요일 10:00 KST까지 스모크 테스트를 재실행하고 결과 공유",
      "due": "금요일 10:00 KST",
      "status": "확정",
      "source_certainty": "high"
    },
    {
      "owner": "Doyun",
      "task": "금요일 12:00 KST까지 failure triage note를 `action_items.md`에 작성",
      "due": "금요일 12:00 KST",
      "status": "확정",
      "source_certainty": "high"
    },
    {
      "owner": "Hara",
      "task": "Minjun의 스모크 결과 공유 후 생성된 tarball 경로 확인",
      "due": "미확정(결과 공유 후)",
      "status": "확정(조건부)",
      "source_certainty": "high"
    },
    {
      "owner": "미지정",
      "task": "README 설치 단계 최신성 검토(목요일 가능 시)",
      "due": "목요일(목표) / 미정",
      "status": "진행중 아님(책임자 미정)",
      "source_certainty": "high"
    }
  ],
  "followup_note": {
    "what_to_check_next": [
      "현재 공개 릴리스 상태 업데이트: 금요일 15:00 KST 기준 smoke pass 여부 확인",
      "Minjun의 스모크 결과 공유 후 Hara의 tarball 경로 확인 결과 수집",
      "Doyun이 작성한 failure triage note의 존재와 내용 반영",
      "README 검토가 미지정 소유자 없이 길게 미뤄지지 않는지 소유자 지정 여부 확인",
      "최종 릴리스 승인 권한자와 릴리스 노트(수요일 stretch goal 포함 여부) 의사결정 정리"
    ],
    "what_not_to_invent": [
      "고객명, 파트너사명, 예산, 보안사고, 장애, 법무 승인 필요성, 소유자 미지정 항목의 실제 담당자, 마감시간(회의록에 없는) 등은 추측해 넣지 않음",
      "제공되지 않은 성과지표(KPI), 비용/일정 범위, 외부 제약 조건, 추가 정책 준수 항목을 임의 구성하지 않음"
    ]
  },
  "non_invention_rules": [
    "회의에 등장한 항목(프로젝트 코드/참석자/결정사항/리스크/질문) 외의 사실을 추가 생성하지 않는다.",
    "고객/파트너, 예산, 보안사고, 장애, 법무 승인 요건은 원문에서 명시되지 않았으므로 비어있거나 미정으로만 표기한다.",
    "담당자가 지정되지 않은 항목에 임의의 owner를 부여하지 않는다.",
    "마감 시각이 없는 작업에 임의로 기한을 만들지 않는다.",
    "수요일 목표를 공개 확정일로 오해하지 않고 내부 stretch goal으로만 기록한다."
  ]
}
